"use client";
// Generated by OrchestKit Claude Plugin
// D2 component lift (docs-site design overhaul)

import { useEffect, useRef, useState } from "react";

interface NumberTickerProps {
  value: number;
  /** milliseconds the count-up animation runs (default 900ms) */
  durationMs?: number;
  className?: string;
}

/**
 * NumberTicker — counts up from 0 to `value` once the element scrolls into
 * view, then holds. Uses requestAnimationFrame with an ease-out curve.
 *
 * Motion: under prefers-reduced-motion the final value is rendered
 * immediately (no animation), so the number is always readable.
 *
 * Renders an inline <span> with tabular-nums so digit width stays stable
 * during the count. The initial SSR/first-paint value is `value` itself,
 * keeping the number correct with JS disabled and for crawlers.
 */
export function NumberTicker({ value, durationMs = 900, className }: NumberTickerProps) {
  const ref = useRef<HTMLSpanElement>(null);
  const [display, setDisplay] = useState(value);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const prefersReduced =
      typeof window !== "undefined" &&
      window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReduced) {
      setDisplay(value);
      return;
    }

    let raf = 0;
    let start = 0;
    const run = () => {
      start = 0;
      setDisplay(0);
      const step = (ts: number) => {
        if (start === 0) start = ts;
        const t = Math.min((ts - start) / durationMs, 1);
        const eased = 1 - (1 - t) ** 3; // easeOutCubic
        setDisplay(Math.round(eased * value));
        if (t < 1) raf = requestAnimationFrame(step);
      };
      raf = requestAnimationFrame(step);
    };

    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            run();
            observer.disconnect();
            break;
          }
        }
      },
      { threshold: 0.4 }
    );
    observer.observe(el);

    return () => {
      observer.disconnect();
      if (raf) cancelAnimationFrame(raf);
    };
  }, [value, durationMs]);

  // Reserve the final value's rendered width so counting up from 0 (1 char) to
  // the target (N chars) never reflows surrounding layout — tabular-nums alone
  // equalizes digit widths but not the count of digits. inline-block + a ch
  // min-width sized to the final string is a zero-CLS guarantee.
  const reserveCh = value.toLocaleString().length;

  return (
    <span
      ref={ref}
      className={`inline-block text-right tabular-nums ${className ?? ""}`}
      style={{ minInlineSize: `${reserveCh}ch` }}
    >
      {display.toLocaleString()}
    </span>
  );
}

export default NumberTicker;
